xwikidoc.content:
{{include reference="AppWithinMinutes.VelocityMacros" /}}

This page provides a reusable JavaScript helper (the {{code}}xwiki-appwithinminutes-csrf{{/code}} RequireJS module) that lets a page
recover gracefully when an AJAX request is rejected because the CSRF (form) token has expired (for instance after a
server restart). Load this extension with {{code}}#set ($discard = $xwiki.jsx.use('AppWithinMinutes.Code.CSRFTokenRefresh')){{/code}}
then, from the failure handler of your request:

{{code language="javascript"}}
require(['xwiki-appwithinminutes-csrf'], function(csrf) {
  csrf.recoverFromExpiredToken(response, function(newToken) {
    // Retry the request with the refreshed token.
  });
});
{{/code}}

property.code:
/*
 * Reusable helper to recover gracefully when an AJAX request is rejected (HTTP 403) because the CSRF (form) token
 * expired, e.g. after a server restart. The server is expected to answer such a 403 with the JSON shape produced by
 * XWikiAction#csrfTokenCheck: {"errorType": "CSRF", "newToken": "..."}.
 */
define('xwiki-appwithinminutes-csrf-messages', {
  prefix: 'csrf.error.',
  keys: ['message', 'causes.introduction', 'causes.stalesession', 'causes.forgedrequest', 'resubmit.question',
    'resubmit.question.no', 'resubmit.question.yes']
});

define('xwiki-appwithinminutes-csrf', ['xwiki-l10n!xwiki-appwithinminutes-csrf-messages'], function (l10n) {
  'use strict';

  // Update the token everywhere it is stored in the page so that any subsequent request uses the fresh one.
  const refreshToken = function (newToken) {
    document.querySelectorAll('input[name="form_token"]').forEach(function (input) {
      input.value = newToken;
    });
    if (window.XWiki?.meta) {
      XWiki.meta.form_token = newToken;
    }
  };

  // Extract the fresh token from a 403 response carrying the {"errorType": "CSRF", "newToken": "..."} JSON body.
  const extractNewToken = function (response) {
    if (response?.status !== 403) {
      return null;
    }
    let json = response.responseJSON;
    if (!json) {
      try {
        json = JSON.parse(response.responseText);
      } catch (e) {
        return null;
      }
    }
    return json?.errorType === 'CSRF' ? json.newToken : null;
  };

  return {
    /**
     * Recover from a request that was rejected because the CSRF (form) token expired.
     *
     * IMPORTANT: this must only be called in reaction to a genuine user-triggered action. It asks the user, through
     * an explicit confirmation, whether to refresh the security token and retry; it never refreshes the token
     * silently. When the user confirms, the new token is written everywhere it is stored in the page (the form_token
     * inputs and XWiki.meta) and the provided callback is invoked so that the caller can retry its request.
     *
     * @param response the failed AJAX response; recovery only happens when it is a 403 carrying the CSRF JSON body
     * @param onConfirm a function called with the new token once the user confirmed and the token has been refreshed
     * @return true if the response was a recoverable CSRF error and the confirmation has been displayed, false
     *   otherwise (in which case the caller should handle the failure on its own)
     */
    recoverFromExpiredToken: function (response, onConfirm) {
      const newToken = extractNewToken(response);
      if (!newToken) {
        return false;
      }
      // Same modal (id and CSS classes) as the one displayed by actionButtons.js when a document save is rejected
      // because of an expired CSRF token, so that both flows look and behave consistently.
      const createContent = function (modal) {
        // Duplicates resubmit.vm to align user experience while make it easy to backport the code to older versions.
        const content = new Element('div', {'class': 'modal-popup', 'id': 'csrf-warning-modal'});
        content.insert(`<p class="main-explanation">${l10n.get('message')}</p>` +
          `<p class="resubmit-causes-introduction">${l10n.get('causes.introduction')}</p>` +
          '<ul class="resubmit-causes">' +
          `<li>${l10n.get('causes.stalesession')}</li>` +
          `<li>${l10n.get('causes.forgedrequest')}</li>` +
          '</ul>' +
          `<div class="resubmit-question">${l10n.get('resubmit.question')}</div>`);

        const buttonsDiv = new Element('div', {'class': 'csrf-warning-buttons'});
        const cancelButton = new Element('button',
          {'class': 'resubmit-primary btn btn-primary', 'id': 'cancel-save-csrf'});
        cancelButton.insert(l10n.get('resubmit.question.no'));
        cancelButton.on('click', function () {
          modal.closeDialog();
        });
        buttonsDiv.insert(cancelButton);

        const retryButton = new Element('button',
          {'class': 'btn btn-default resubmit-secondary', 'id': 'force-save-csrf'});
        retryButton.insert(l10n.get('resubmit.question.yes'));
        retryButton.on('click', function () {
          modal.closeDialog();
          refreshToken(newToken);
          onConfirm(newToken);
        });
        buttonsDiv.insert(retryButton);

        content.insert(buttonsDiv);
        return content;
      };

      const ModalClass = Class.create(XWiki.widgets.ModalPopup, {
        initialize: function ($super) {
          $super(createContent(this), {'show': {method: this.showDialog, keys: []}}, {
            displayCloseButton: false,
            verticalPosition: 'center',
            backgroundColor: '#FFF',
            removeOnClose: true
          });
          this.showDialog();
        }
      });
      new ModalClass();
      return true;
    }
  };
});
